// Validate the webhook payload and build a Firestore REST typed-value document
// for the bodyweight/{uid}_{date} upsert (see integrations/firestore-model.md).

const config = $('Config').first().json;
const hook = $('Weight webhook').first().json;

const secret = hook.headers?.['x-cornerman-secret'] ?? '';
if (!config.sharedSecret || secret !== config.sharedSecret) {
  throw new Error('Bad or missing x-cornerman-secret header.');
}

const body = hook.body ?? {};

// Shortcuts on a Dutch locale can send "82,4" — normalise the decimal comma.
const raw = body.weightKg ?? body.weight;
const weightKg = Math.round(parseFloat(String(raw).replace(',', '.')) * 10) / 10;
if (!Number.isFinite(weightKg) || weightKg < 30 || weightKg > 250) {
  throw new Error(`weightKg missing or out of range (30-250): ${JSON.stringify(raw)}`);
}

// Prefer the sample's own date (weigh-in day), fall back to today in Amsterdam.
let date = String(body.date ?? '').slice(0, 10);
if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
  date = new Intl.DateTimeFormat('en-CA', { timeZone: 'Europe/Amsterdam' }).format(new Date());
}

return [{
  json: {
    docId: `${config.uid}_${date}`,
    firestoreBody: {
      fields: {
        uid: { stringValue: config.uid },
        date: { stringValue: date },
        weightKg: { doubleValue: weightKg },
        updatedAt: { timestampValue: new Date().toISOString() }
      }
    }
  }
}];
